     return new ICmpInst(Pred, LShr, Constant::getNullValue(LShr->getType()));
   }

+  // (icmp eq/ne (and (add A, -1), Msk), 0)
+  //    -> (icmp eq/ne (and A, Msk), 1)
+  // This is valid for any mask that includes bit 0.
+  {
+    Value *A;
+    const APInt *Msk;
+    if (C.isZero() &&
+        match(And, m_And(m_OneUse(m_Add(m_Value(A), m_AllOnes())),
+                         m_APInt(Msk))) &&
+        (*Msk)[0]) {
+      Value *MaskA = Builder.CreateAnd(A, ConstantInt::get(A->getType(), *Msk));
+      return new ICmpInst(Pred, MaskA,
+                          ConstantInt::get(MaskA->getType(),
+                                           APInt(Msk->getBitWidth(), 1)));
+    }
+  }
+
   // (icmp eq/ne (and (add A, Addend), Msk), C)
   //    -> (icmp eq/ne (and A, Msk), (and (sub C, Addend), Msk))
